#[test]
fn test_in_subquery_against_a_newtype_column() {
    // A `ColumnType` newtype operand matches a subquery projecting the same newtype column. (The
    // value-type guard rejects mixing it with an `i32`-projecting subquery — see the compile-fail
    // test `in_subquery_type_mismatch`.)
    let q = TestConnection
        .from::<Event>()
        .where_correlated(|(event,), sub| {
            event.ledger_ref.in_subquery(
                sub.from::<Event>()
                    .select_subquery(|(other,)| other.ledger_ref),
            )
        })
        .select(|(event,)| event.id);

    assert_eq!(
        q.to_sql(),
        "SELECT q0_0.id AS id FROM events AS q0_0 WHERE (q0_0.ledger_ref IN (SELECT \
         q1_0.ledger_ref AS ledger_ref FROM events AS q1_0))"
    );
}

#[test]
fn test_in_subquery_against_a_nullable_column_is_allowed() {
    // `x IN (SELECT nullable_col …)` is valid SQL: the column kind's value type is the non-null
    // inner type, so a `String` operand matches a nullable `Option<String>` projected column.
    let q = TestConnection
        .from::<User>()
        .where_correlated(|(user,), sub| {
            user.name
                .in_subquery(sub.from::<Event>().select_subquery(|(event,)| event.label))
        })
        .select(|(user,)| user.id);

    assert_eq!(
        q.to_sql(),
        "SELECT q0_0.id AS id FROM public.users AS q0_0 WHERE (q0_0.name IN (SELECT \
         q1_0.label AS label FROM events AS q1_0))"
    );
}

#[test]
fn test_scalar_subquery_of_a_nullable_column_is_null_testable() {
    // A scalar subquery over a nullable column keeps its nullable kind, so `is_null` is available.
    let q = TestConnection
        .from::<User>()
        .where_correlated(|(_user,), sub| {
            scalar_subquery(
                sub.from::<Event>()
                    .where_(|event| event.ledger_ref.equals(LedgerRef(1)))
                    .select_subquery(|(event,)| event.label),
            )
            .is_null()
        })
        .select(|(user,)| user.id);

    assert_eq!(
        q.to_sql(),
        "SELECT q0_0.id AS id FROM public.users AS q0_0 WHERE ((SELECT q1_0.label AS label \
         FROM events AS q1_0 WHERE (q1_0.ledger_ref = ?)) IS NULL)"
    );
}

#[test]
fn test_window_aggregate_over_partition_and_order() {
    let q = TestConnection.from::<Post>().select(|(post,)| {
        post.user_id
            .sum()
            .over(|w| w.partition_by(post.user_id).order_by(post.id.asc()))
    });
    assert_eq!(
        q.to_sql(),
        "SELECT SUM(q0_0.user_id) OVER (PARTITION BY q0_0.user_id ORDER BY q0_0.id ASC) AS expr \
         FROM posts AS q0_0"
    );
}

#[test]
fn test_window_partition_only_and_order_only() {
    let part = TestConnection
        .from::<Post>()
        .select(|(post,)| post.user_id.sum().over(|w| w.partition_by(post.user_id)));
    assert_eq!(
        part.to_sql(),
        "SELECT SUM(q0_0.user_id) OVER (PARTITION BY q0_0.user_id) AS expr FROM posts AS q0_0"
    );

    let ord = TestConnection
        .from::<Post>()
        .select(|(post,)| post.user_id.sum().over(|w| w.order_by(post.id.desc())));
    assert_eq!(
        ord.to_sql(),
        "SELECT SUM(q0_0.user_id) OVER (ORDER BY q0_0.id DESC) AS expr FROM posts AS q0_0"
    );
}

#[test]
fn test_window_multiple_partition_and_order_terms() {
    let q = TestConnection.from::<Post>().select(|(post,)| {
        post.id.sum().over(|w| {
            w.partition_by(post.user_id)
                .partition_by(post.id)
                .order_by(post.id.asc())
                .order_by(post.user_id.desc())
        })
    });
    assert_eq!(
        q.to_sql(),
        "SELECT SUM(q0_0.id) OVER (PARTITION BY q0_0.user_id, q0_0.id ORDER BY q0_0.id ASC, \
         q0_0.user_id DESC) AS expr FROM posts AS q0_0"
    );
}

#[test]
fn test_window_ranking_functions_render() {
    let row_num = TestConnection.from::<Post>().select(|(post,)| {
        row_number().over(|w| w.partition_by(post.user_id).order_by(post.id.asc()))
    });
    assert_eq!(
        row_num.to_sql(),
        "SELECT ROW_NUMBER() OVER (PARTITION BY q0_0.user_id ORDER BY q0_0.id ASC) AS expr \
         FROM posts AS q0_0"
    );

    let ranked = TestConnection
        .from::<Post>()
        .select(|(post,)| rank().over(|w| w.order_by(post.id.desc())));
    assert_eq!(
        ranked.to_sql(),
        "SELECT RANK() OVER (ORDER BY q0_0.id DESC) AS expr FROM posts AS q0_0"
    );

    let dense = TestConnection
        .from::<Post>()
        .select(|(post,)| dense_rank().over(|w| w.order_by(post.id.asc())));
    assert_eq!(
        dense.to_sql(),
        "SELECT DENSE_RANK() OVER (ORDER BY q0_0.id ASC) AS expr FROM posts AS q0_0"
    );
}

